import React from 'react';

const NovedadesSection = () => {
  return (
    <section className="novedades-section">
      <h2>Novedades</h2>
      <div className="novedades-content">
        <p>Latest updates and news about Skyia.</p>
      </div>
    </section>
  );
};

export default NovedadesSection;

import { db } from './dbService';

export const saveReport = async (reportData: any, mode: 'local' | 'cloud') => {
  if (mode === 'local') {
    localStorage.setItem('skyiaReport', JSON.stringify(reportData));
  } else {
    await db.reports.add(reportData);
  }
};

export const loadReport = async (mode: 'local' | 'cloud') => {
  if (mode === 'local') {
    return JSON.parse(localStorage.getItem('skyiaReport') || '{}');
  } else {
    const snapshot = await db.reports.get();
    return snapshot.data();
  }
};

